var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"에휴......","JPN":"まったく……","ENG":"Ugh...","TWN":"唉……"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"여기도 완전히 박살 나 버렸네.","JPN":"ここも完全に破壊されてしまったな。","ENG":"So this place is completely destroyed, too.","TWN":"這裡也被破壞了。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이제야 겨우 정착한 줄 알았는데, 이러면 또 떠돌이 신세잖아.","JPN":"やっと定着したと思ったが……こんなんじゃあ、また放浪の身になるじゃないか。","ENG":"I thought we were finally settling down. Now we've got to hit the road again.","TWN":"還以為終於定居了，這樣一來又得流浪了。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그 괴물이 강림했을 때의 여파가 지하실 통로 너머까지 퍼져나갔으니까.","JPN":"あの化け物が降臨したときの余波が地下室の通路の先まで広まっちゃったからね。","ENG":"Yeah, who knew the effects of that monster's arrival would reach beyond the portal all the way out here?","TWN":"那個怪物降臨的時候，直接影響了地下室通道的那一邊。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그나마 운 나쁘게 휘말린 사람이 없어서 다행이야.","JPN":"でも、巻き込まれた人がいなくてよかったわ。","ENG":"At least nobody got swept up in all of that creepy destruction.","TWN":"所幸沒有人被捲入。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래. 그 괴물 말이야.","JPN":"そうだよ。あの怪物だ。","ENG":"Speaking of that monster...","TWN":"是啊，那個怪物。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하아...... 최초의 인형이나 발푸르기스 성 보수작업만으로도 머리 아파 죽겠는데 그 괴물은 또 뭐람?","JPN":"はあ……最初の人形やヴァルプルギス城の補修作業だけで\\n十分大変なのに、あの怪物は何なんだ。","ENG":"What's the deal with that monster? It's already enough tracking down the Original Puppet and repairing the Walpurgis Castle.","TWN":"哈啊……最初的木偶和魔女之夜城的修繕工作已經讓我很頭疼了，怎麼還出現個怪物？"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"인형의 주인을 벌레 잡듯 없애 버리다니...... 그런 괴물이 갑자기 어디서 나타난 걸까......","JPN":"人形の持ち主を完膚なきまでに消してしまうなんて……\\nあんな化け物どこから現れたんだろう……","ENG":"I mean, it just got rid of the Puppet Master instantly, as if swatting a fly. Where did something like that come from?","TWN":"木偶之主在它面前就像個螻蟻……那怪物到底是從哪裡來的呢……"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"괴물에 대해서는 앞으로 알아 봐야겠지만, 새로 알게 된 사실도 하나 있어.","JPN":"怪物については今から調べる必要があるけど、初めて知った事実も一つあったわ。","ENG":"We'll have to do more research on the monster, but there is something new we could learn.","TWN":"那個怪物還得再調查一下，不過我倒是有新發現。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭔데?","JPN":"何だ？","ENG":"And what's that?","TWN":"是什麼？"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그 무시무시한 최초의 인형이 사실은 마조히스트 변태였다는 것.","JPN":"あの恐ろしい最初の人形は、実はドMだったってこと。","ENG":"That the formidable Original Puppet turned out to be just a perverted masochist.","TWN":"那個可怕的最初的木偶其實就是個超級受虐狂。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"풉! 하하하!","JPN":"ぷっ！　ははは！","ENG":"Pfft! Hah hah hah!","TWN":"噗！哈哈哈！"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아, 그건 정말 웃겼어.","JPN":"ああ、今のは本当にウケた。","ENG":"Ah, good one.","TWN":"啊，那確實很搞笑。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"자기가 만든 인형을 주인님이라고 부르면서 괴롭혀 달라고 졸랐다는 거 아냐.","JPN":"自分で作った人形をマスターと呼びながら、苦しめてほしいとねだっていたな。","ENG":"Just imagine her begging her own puppet to torture her, calling it \\"Master.\\"","TWN":"居然把自己做成的木偶叫做主人，還讓木偶折磨自己。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"나였으면 부끄러워서라도 평생 성 안에 틀어박혀 있었을 걸.","JPN":"妾だったら恥ずかしくて一生城の中に閉じこもっただろう。","ENG":"I'd be so ashamed of myself that I would have never left that castle, if I were her.","TWN":"換做是我，丟臉丟得都不敢走出城門，估計一輩子就老死在城裡了。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그렇긴 한데, 너 그 얘기 들을 때는 고개도 못 들고 부들부들 떨고 있지 않았어?","JPN":"それはそうだけど……あなたその話を聞いてる時、\\n頭を下げたままぶるぶる震えてなかった？","ENG":"Says the person who was too scared to even look up when she told us that. You were trembling like a lost puppy.","TWN":"可是，那個傢伙那麼說的時候，妳不是連頭都不敢抬，一直在那裡抖個不停嗎？"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그, 그건 어쩔 수 없잖아!","JPN":"そ、それは仕方ないだろう！","ENG":"W-well, I couldn't help it!","TWN":"那、那是沒辦法吧！"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그 녀석은...... 우리 세계를 멸망시킨 원흉이니까.","JPN":"あいつは……妾たちの世界を滅ぼした元凶だからな。","ENG":"She... destroyed our home world.","TWN":"因為那個傢伙……是毀滅了我們世界的真凶。"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_STREGA_03","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};